class Point {
    static class Builder {
        private int x, y;
        Builder x(int x) { this.x = x; return this; }
        Builder y(int y) { this.y = y; return this; }
        Point build() { return new Point(x, y); }
    }
}
// Usage: new Point.Builder().x(10).y(20).build();
// WHY? Just use: new Point(10, 20);

goodCode:
// Just use a simple constructor
class Point {
    final int x, y;
    Point(int x, int y) { this.x = x; this.y = y; }
}
// Usage: new Point(10, 20); -- clean, direct, obvious

