public Meal build() {
    if (bun == null) throw new IllegalStateException("Bun is required!");
    if (pattyCount < 1) throw new IllegalStateException("At least 1 patty!");
    if (bun.equals("gluten-free") && bacon)
        throw new IllegalStateException("No bacon with gluten-free bun!");
    return new Meal(this);
}

