goodCode:
class Payment {
    private final String orderId;    // final -- identity never changes
    private final double amount;     // final -- identity never changes
    private PaymentStatus status;    // mutable -- lifecycle field

    public void setStatus(PaymentStatus s) { this.status = s; } // OK!
    // No setter for orderId or amount -- Builder's validation holds
}

